sql:
SELECT house_id, house_type, energy_efficiency_rating
FROM houses
WHERE energy_efficiency_rating > 80;

SELECT efficiency_rating, improvement_tips
FROM energy_efficiency
WHERE year = 2011 AND month = 8;

SELECT house_id, AVG(energy_produced) AS average_energy_production
FROM energy_production
GROUP BY house_id;

SELECT COUNT(DISTINCT house_id) AS "Households with above 80 efficiency rating"
FROM energy_efficiency
WHERE efficiency_rating > 80;

SELECT AVG(energy_saving) 
FROM energy_efficiency 
WHERE house_id = 0 AND month = 1;

SELECT house_id, AVG(efficiency_rating) AS AvgRating
FROM energy_efficiency
GROUP BY house_id;

SELECT reading_value
FROM sensor_readings
WHERE sensor_id = 0;

SELECT house_id, energy_consumed
FROM energy_consumption
WHERE year = 2010 AND month = 7;

external_knowledge:
- Energy efficiency status is determined by the average energy consumed: 'high' if ≤ 1000, 'medium' if > 1000 and ≤ 2000, 'low' if > 2000;
- Recent energy use refers to the latest recorded energy consumption data in the database;
- Identifying information includes unique identifier, type, location, and address of the household.

sql:
SELECT house_id
FROM energy_production_history
WHERE energy_produced < 600;

SELECT house_id, location, energy_efficiency_rating
FROM houses
WHERE energy_efficiency_rating > (
    SELECT AVG(energy_efficiency_rating) FROM houses
)
ORDER BY energy_efficiency_rating DESC;

SELECT year, energy_produced
FROM energy_production
WHERE peak_hour_flag = 1;

external_knowledge:
Summer month refers to August in this context; medium-level advice means recommendations with priority 'medium'; regular daily schedule means notification frequency is set to 'daily'.;
The preference for updates is related to notification preferences for daily notifications.;
Energy-saving advice is found in the recommendations table with a priority level indicated as 'medium'.;
